/**
 * Code Send to Sheet
 * - Reads all rows from "Read Existing"
 * - Reads API response from "Theirstack API Request"
 * - Emits only NEW jobs (not in sheet) as rows ready for Append
 */

// 1) Build sets of existing IDs and links from the sheet
const existingRows = $items('Read Existing', 0, 0) || [];
const existingIds   = new Set(
  existingRows
    .map(i => String(i.json.id ?? '').trim())
    .filter(Boolean)
);
const existingLinks = new Set(
  existingRows
    .map(i => String(i.json.apply_link ?? '').trim())
    .filter(Boolean)
);

// 2) Flatten all jobs from the API node
const apiItems = $items('Theirstack API Request', 0, 0) || [];
const allJobs = [];

for (const it of apiItems) {
  // API may return an object or an array with an object
  const containers = Array.isArray(it.json) ? it.json : [it.json];
  for (const c of containers) {
    const jobs = (c && Array.isArray(c.data)) ? c.data : [];
    allJobs.push(...jobs);
  }
}

// 3) Keep only jobs not already present (by id OR apply_link)
const isNew = (job) => {
  const id  = String(job?.id ?? '').trim();
  const url = String(job?.final_url || job?.url || '').trim();
  if (!id && !url) return false; // skip empty
  if (id && existingIds.has(id)) return false;
  if (url && existingLinks.has(url)) return false;
  return true;
};

let newJobs = allJobs.filter(isNew);

// 4) (Optional) sort by date_posted ascending (oldest → newest)
newJobs.sort((a, b) => {
  const ta = new Date(a?.date_posted ?? 0).getTime() || 0;
  const tb = new Date(b?.date_posted ?? 0).getTime() || 0;
  return ta - tb;
});

// 5) Map to your sheet columns
const DEFAULT_STATUS = 'To Apply';
const rows = newJobs.map(job => ({
  id: job.id ?? '',
  date_posted: job.date_posted ?? '',
  company: job.company ?? '',
  title: job.job_title ?? '',
  apply_link: job.final_url || job.url || '',
  status: DEFAULT_STATUS,
}));

// 6) Emit one item per new row for the Google Sheets "Append" node
return rows.map(r => ({ json: r }));

