for (const it of apiItems) {
  // API may return an object or an array with an object
  const containers = Array.isArray(it.json) ? it.json : [it.json];
  for (const c of containers) {
    const jobs = (c && Array.isArray(c.data)) ? c.data : [];
    allJobs.push(...jobs);
  }
}

// 3) Keep only jobs not already present (by id OR apply_link)
const isNew = (job) => {
