};

let newJobs = allJobs.filter(isNew);

// 4) (Optional) sort by date_posted ascending (oldest → newest)
newJobs.sort((a, b) => {
  const ta = new Date(a?.date_posted ?? 0).getTime() || 0;
  const tb = new Date(b?.date_posted ?? 0).getTime() || 0;
  return ta - tb;
});


const count = newJobs.length;

let text;
if (count === 0) {
  text = "✅ No new jobs for DA found.\nHave a good day, Dear 😄";
} else {
  // Format each new job into a Slack-friendly line
  const lines = newJobs.map((r, idx) => {
    const company = r.company || 'Unknown Company';
    const title   = r.title   || 'Untitled Job';
    const date    = r.date_posted || 'Unknown Date';
    const link    = r.apply_link || '';
    return `${idx + 1}. *${company}*: *${title}*\nPosted: ${date}\n<${link}>`;
  });

  text = `*🎉 ${count} new job${count > 1 ? 's' : ''} added to the sheet!* \n\n` +
         lines.join('\n\n');
}

// Always emit exactly one item so the Slack node runs once
return [{ json: { text } }];

// Code node AFTER "Append row in sheet"
const appended = $input.all();   // rows that were actually appended

if (!appended.length) {
  return [{ json: { text:"No new jobs for DA found. Have a good day, Dear 😄" } }];
}

const lines = appended.map((it, idx) => {
  const r = it.json || {};
  const company = r.company || 'Unknown Company';
  const title   = r.title   || 'Untitled Job';
  const date    = r.date_posted || 'Unknown Date';
  const link    = r.apply_link || '';
  return `${idx + 1}. *${company}*: *${title}*\nPosted: ${date}\n<${link}>`;
});

const text = `*${appended.length} new job${appended.length === 1 ? '' : 's'} added to the sheet*\n\n${lines.join('\n\n')}`;
return [{ json: { text } }];
